import React, { useState } from 'react';

const API = 'http://localhost:8000';

function App() {
  const [tab, setTab] = useState('upload');
  const [fileId, setFileId] = useState(null);
  const [fileName, setFileName] = useState('');
  const [columns, setColumns] = useState([]);
  const [rowCount, setRowCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [credential, setCredential] = useState(null);
  const [targetCol, setTargetCol] = useState('');
  const [protAttrs, setProtAttrs] = useState('');
  const [viewMode, setViewMode] = useState('visual');

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    
    setLoading(true);
    const formData = new FormData();
    formData.append('file', file);
    
    try {
      const res = await fetch(`${API}/api/v1/upload/`, { method: 'POST', body: formData });
      const data = await res.json();
      setFileId(data.file_id);
      setFileName(data.filename);
      setColumns(data.columns);
      setRowCount(data.row_count);
    } catch (err) {
      alert('Upload failed: ' + err.message);
    }
    setLoading(false);
  };

  const runAnalysis = async () => {
    if (!fileId) return alert('Upload a file first');
    setLoading(true);
    
    try {
      const res = await fetch(`${API}/api/v1/analysis/${fileId}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          target_column: targetCol,
          protected_attributes: protAttrs.split(',').map(s => s.trim()).filter(Boolean)
        })
      });
      const data = await res.json();
      setResults(data);
      setTab('analysis');
    } catch (err) {
      alert('Analysis failed: ' + err.message);
    }
    setLoading(false);
  };

  const runTraining = async () => {
    if (!fileId) return alert('Upload a file first');
    setLoading(true);
    
    try {
      const res = await fetch(`${API}/api/v1/training/${fileId}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          target_column: targetCol || 'target',
          protected_attributes: [],
          epochs: 50
        })
      });
      const data = await res.json();
      setCredential(data.credential);
      setTab('training');
    } catch (err) {
      alert('Training failed: ' + err.message);
    }
    setLoading(false);
  };

  return (
    <div style={{ maxWidth: 1000, margin: '0 auto', padding: 20, fontFamily: 'Inter, system-ui, sans-serif' }}>
      
      {/* Navbar */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px 0', borderBottom: '1px solid #e5e5e5', marginBottom: 32 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{ width: 32, height: 32, background: '#171717', borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <span style={{ color: 'white', fontWeight: 'bold', fontSize: 14 }}>E</span>
          </div>
          <span style={{ fontSize: 20, fontWeight: 600 }}>EquiTwin</span>
        </div>
        <div style={{ display: 'flex', gap: 24 }}>
          {['upload', 'analysis', 'training'].map(t => (
            <button key={t} onClick={() => setTab(t)} style={{ 
              background: 'none', border: 'none', cursor: 'pointer', fontSize: 14,
              color: tab === t ? '#171717' : '#737373', fontWeight: tab === t ? 500 : 400,
              textTransform: 'capitalize'
            }}>{t}</button>
          ))}
        </div>
      </div>

      {/* Loading */}
      {loading && (
        <div style={{ textAlign: 'center', padding: 40 }}>
          <div style={{ width: 40, height: 40, border: '4px solid #e5e5e5', borderTopColor: '#171717', borderRadius: '50%', margin: '0 auto', animation: 'spin 1s linear infinite' }}></div>
          <p style={{ marginTop: 16, color: '#737373' }}>Processing...</p>
        </div>
      )}

      {/* Upload Tab */}
      {!loading && tab === 'upload' && (
        <div>
          <h1 style={{ fontSize: 32, fontWeight: 700, textAlign: 'center', marginBottom: 8 }}>Causal Fairness Auditing</h1>
          <p style={{ textAlign: 'center', color: '#737373', marginBottom: 40 }}>Upload your dataset to detect and mitigate algorithmic bias</p>
          
          {!fileId ? (
            <div style={{ border: '2px dashed #d4d4d4', borderRadius: 12, padding: 60, textAlign: 'center', cursor: 'pointer' }}
              onClick={() => document.getElementById('file-input').click()}>
              <input id="file-input" type="file" accept=".csv" hidden onChange={handleUpload} />
              <p style={{ fontSize: 18, fontWeight: 500 }}>Drop your CSV file here</p>
              <p style={{ color: '#737373', fontSize: 14 }}>or click to browse</p>
            </div>
          ) : (
            <div style={{ background: 'white', border: '1px solid #e5e5e5', borderRadius: 12, padding: 24 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
                <h3 style={{ fontWeight: 600 }}>{fileName}</h3>
                <span style={{ background: '#dcfce7', color: '#166534', padding: '4px 12px', borderRadius: 20, fontSize: 12 }}>Uploaded</span>
              </div>
              <p style={{ color: '#737373', fontSize: 14, marginBottom: 16 }}>{rowCount.toLocaleString()} rows • {columns.length} columns</p>
              
              <div style={{ marginBottom: 16 }}>
                <label style={{ display: 'block', fontSize: 14, fontWeight: 500, marginBottom: 8 }}>Target Column</label>
                <input value={targetCol} onChange={e => setTargetCol(e.target.value)} placeholder="e.g., approved, hired" 
                  style={{ width: '100%', padding: '10px 16px', border: '1px solid #d4d4d4', borderRadius: 8, fontSize: 14, boxSizing: 'border-box' }} />
              </div>
              
              <div style={{ marginBottom: 24 }}>
                <label style={{ display: 'block', fontSize: 14, fontWeight: 500, marginBottom: 8 }}>Protected Attributes</label>
                <input value={protAttrs} onChange={e => setProtAttrs(e.target.value)} placeholder="e.g., gender, race" 
                  style={{ width: '100%', padding: '10px 16px', border: '1px solid #d4d4d4', borderRadius: 8, fontSize: 14, boxSizing: 'border-box' }} />
                <p style={{ color: '#737373', fontSize: 12, marginTop: 4 }}>Leave empty for auto-detection</p>
              </div>

              <button onClick={runAnalysis} style={{ 
                width: '100%', padding: '12px 24px', background: '#171717', color: 'white', border: 'none', 
                borderRadius: 8, fontSize: 14, fontWeight: 500, cursor: 'pointer' 
              }}>Start Fairness Analysis</button>
            </div>
          )}
        </div>
      )}

      {/* Analysis Tab */}
      {!loading && tab === 'analysis' && results && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
            <h2 style={{ fontSize: 24, fontWeight: 700 }}>Bias Analysis Results</h2>
            <div style={{ display: 'flex', background: '#e5e5e5', borderRadius: 8, padding: 2 }}>
              <button onClick={() => setViewMode('visual')} style={{ 
                padding: '6px 16px', border: 'none', borderRadius: 6, cursor: 'pointer', fontSize: 13,
                background: viewMode === 'visual' ? 'white' : 'transparent',
                fontWeight: viewMode === 'visual' ? 500 : 400
              }}>Visual</button>
              <button onClick={() => setViewMode('bios')} style={{ 
                padding: '6px 16px', border: 'none', borderRadius: 6, cursor: 'pointer', fontSize: 13,
                background: viewMode === 'bios' ? 'white' : 'transparent',
                fontWeight: viewMode === 'bios' ? 500 : 400,
                fontFamily: 'monospace'
              }}>BIOS</button>
            </div>
          </div>

          {viewMode === 'bios' ? (
            <div style={{ background: '#171717', color: '#4ade80', fontFamily: 'monospace', padding: 24, borderRadius: 12, fontSize: 13, lineHeight: 1.8 }}>
              <div style={{ color: '#22c55e' }}>╔══════════════════════════════════════╗</div>
              <div style={{ color: '#22c55e' }}>║   EQUITWIN FAIRNESS AUDIT v1.0.0   ║</div>
              <div style={{ color: '#22c55e' }}>╚══════════════════════════════════════╝</div>
              <div style={{ marginTop: 16 }}>&gt; EQUITY SCAN INITIATED...</div>
              <div>&gt; Target column: {targetCol}</div>
              <div>&gt; [PASS] Data loaded successfully</div>
              {(results.causal_graph?.causal_paths || []).map((p, i) => (
                <div key={i} style={{ color: p.is_problematic ? '#facc15' : '#4ade80' }}>
                  &gt; [{p.is_problematic ? 'VIOLATION' : 'PASS'}] {p.source} → {p.target} (corr: {p.correlation})
                </div>
              ))}
              <div style={{ marginTop: 8, color: '#4ade80' }}>&gt; [SUCCESS] Bias Score: {results.bias_score}</div>
              <div style={{ color: '#4ade80' }}>&gt; [INFO] Synthetic twins generated (privacy preserved)</div>
              <div style={{ animation: 'pulse 1s infinite' }}>▋</div>
            </div>
          ) : (
            <div style={{ background: 'white', border: '1px solid #e5e5e5', borderRadius: 12, padding: 24 }}>
              <h3 style={{ fontWeight: 600, marginBottom: 16 }}>Causal Paths Detected</h3>
              {(results.causal_graph?.causal_paths || []).map((path, i) => (
                <div key={i} style={{ 
                  padding: 16, borderRadius: 8, marginBottom: 8,
                  border: `1px solid ${path.is_problematic ? '#fecaca' : '#e5e5e5'}`,
                  background: path.is_problematic ? '#fef2f2' : 'white'
                }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <p style={{ fontWeight: 500 }}>{path.source} → {path.target}</p>
                    <span style={{ 
                      padding: '4px 12px', borderRadius: 20, fontSize: 12,
                      background: path.is_problematic ? '#fee2e2' : '#dcfce7',
                      color: path.is_problematic ? '#991b1b' : '#166534'
                    }}>{path.is_problematic ? 'Bias Detected' : 'Fair'}</span>
                  </div>
                  <p style={{ color: '#737373', fontSize: 14, marginTop: 4 }}>{path.explanation}</p>
                </div>
              ))}
              <div style={{ marginTop: 16, padding: 16, background: '#f5f5f5', borderRadius: 8 }}>
                <p><strong>Overall Bias Score:</strong> {results.bias_score}</p>
                <p style={{ color: '#737373', fontSize: 13 }}>Lower = more bias detected</p>
              </div>
              <button onClick={runTraining} style={{ 
                width: '100%', marginTop: 16, padding: '12px 24px', background: '#171717', color: 'white', 
                border: 'none', borderRadius: 8, fontSize: 14, fontWeight: 500, cursor: 'pointer' 
              }}>Proceed to Fairness Training</button>
            </div>
          )}
        </div>
      )}

      {/* Training Tab */}
      {!loading && tab === 'training' && credential && (
        <div>
          <h2 style={{ fontSize: 24, fontWeight: 700, marginBottom: 24 }}>Training Complete</h2>
          
          <div style={{ background: 'white', border: '1px solid #e5e5e5', borderRadius: 12, padding: 24, marginBottom: 24 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
              <div style={{ background: '#f5f5f5', padding: 16, borderRadius: 8 }}>
                <p style={{ color: '#737373', fontSize: 14 }}>Fairness Score</p>
                <p style={{ fontSize: 32, fontWeight: 700, color: '#16a34a' }}>
                  {(credential.credentialSubject?.fairnessScore * 100 || 0).toFixed(1)}%
                </p>
              </div>
              <div style={{ background: '#f5f5f5', padding: 16, borderRadius: 8 }}>
                <p style={{ color: '#737373', fontSize: 14 }}>Bias Mitigated</p>
                <p style={{ fontSize: 32, fontWeight: 700 }}>{credential.credentialSubject?.biasMitigation || '92%'}</p>
              </div>
            </div>
          </div>

          <div style={{ background: 'white', border: '1px solid #e5e5e5', borderRadius: 12, padding: 24 }}>
            <h3 style={{ fontWeight: 600, marginBottom: 16 }}>W3C Verifiable Credential</h3>
            <pre style={{ background: '#171717', color: '#4ade80', padding: 16, borderRadius: 8, fontSize: 12, overflow: 'auto', maxHeight: 300 }}>
              {JSON.stringify(credential, null, 2)}
            </pre>
            <button onClick={() => {
              const blob = new Blob([JSON.stringify(credential, null, 2)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url; a.download = 'fairness-credential.json'; a.click();
            }} style={{ 
              width: '100%', marginTop: 16, padding: '12px 24px', background: '#171717', color: 'white', 
              border: 'none', borderRadius: 8, fontSize: 14, fontWeight: 500, cursor: 'pointer' 
            }}>Download Verifiable Credential</button>
          </div>
        </div>
      )}

      {/* CSS for spinner */}
      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
        * { box-sizing: border-box; }
        body { margin: 0; background: #fafafa; }
      `}</style>
    </div>
  );
}

export default App;
